"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["7602"],{1755(i){i.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/pl/blog/welcome","source":"@site/i18n/pl/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Witamy w Wiki Heiman Technology","description":"Witamy w Wiki Heiman Technology! To oficjalna baza wiedzy Heiman Technology, zawieraj\u0105ca dokumentacj\u0119 produkt\xf3w, rozwi\u0105zania techniczne, aktualno\u015Bci bran\u017Cowe i informacje o firmie.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/tags/heiman","description":"Aktualno\u015Bci zwi\u0105zane z Heiman Technology"}],"readingTime":0.71,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Witamy w Wiki Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman oficjalnie wprowadza inteligentny czujnik dymu z obs\u0142ug\u0105 protoko\u0142u Matter","permalink":"/heiman-wiki-public/pl/blog/mdx-blog-post"}},"content":"Witamy w Wiki Heiman Technology! To oficjalna baza wiedzy Heiman Technology, zawieraj\u0105ca dokumentacj\u0119 produkt\xf3w, rozwi\u0105zania techniczne, aktualno\u015Bci bran\u017Cowe i informacje o firmie.\\n\\n{/* truncate */}\\n\\n## O tej witrynie\\n\\nWiki Heiman Technology ma na celu zapewnienie partnerom, programistom i klientom kompleksowych zasob\xf3w technicznych w jednym miejscu, pomagaj\u0105c szybko pozna\u0107:\\n\\n- **Centrum produktowe** \u2014 pe\u0142na gama produkt\xf3w: inteligentne bezpiecze\u0144stwo po\u017Carowe, gazowe, opieka nad seniorami, inteligentne czujniki\\n- **Rozwi\u0105zania** \u2014 kompleksowe rozwi\u0105zania bezpiecze\u0144stwa na poziomie bran\u017Cowym\\n- **Dokumentacja techniczna** \u2014 przewodniki integracji API, instrukcje SDK, podr\u0119czniki instalacji i wdra\u017Cania\\n- **Spostrze\u017Cenia bran\u017Cowe** \u2014 najnowsze trendy i interpretacje polityki w dziedzinie inteligentnego bezpiecze\u0144stwa\\n\\n## Szybka nawigacja\\n\\n- Zobacz [Produkty i rozwi\u0105zania](/docs/tutorial-basics/create-a-page), aby pozna\u0107 linie produkt\xf3w Heiman\\n- Przeczytaj [O firmie](/docs/intro), aby pozna\u0107 histori\u0119 rozwoju Heiman\\n- Odwied\u017A [oficjaln\u0105 stron\u0119 Heiman](https://www.heiman.com.cn), aby uzyska\u0107 wi\u0119cej informacji\\n\\nW razie jakichkolwiek pyta\u0144 zadzwo\u0144 na infolini\u0119 **400-8959-500** lub skontaktuj si\u0119 z konsultantem online."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/pl/blog/mdx-blog-post","source":"@site/i18n/pl/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman oficjalnie wprowadza inteligentny czujnik dymu z obs\u0142ug\u0105 protoko\u0142u Matter","description":"Nowy inteligentny czujnik dymu Heiman HS1SA-M z obs\u0142ug\u0105 protoko\u0142u Matter zosta\u0142 oficjalnie wprowadzony na rynek. Jest to jeden z pierwszych czujnik\xf3w dymu w bran\u017Cy z certyfikatem Matter 1.2.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/pl/blog/tags/matter","description":"Tre\u015Bci zwi\u0105zane z protoko\u0142em Matter"},{"inline":false,"label":"Inteligentne bezpiecze\u0144stwo po\u017Carowe","permalink":"/heiman-wiki-public/pl/blog/tags/smart-fire","description":"Produkty i rozwi\u0105zania inteligentnego bezpiecze\u0144stwa po\u017Carowego"}],"readingTime":0.67,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman oficjalnie wprowadza inteligentny czujnik dymu z obs\u0142ug\u0105 protoko\u0142u Matter","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Witamy w Wiki Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/welcome"},"nextItem":{"title":"Historia rozwoju Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/long-blog-post"}},"content":"Nowy inteligentny czujnik dymu Heiman HS1SA-M z obs\u0142ug\u0105 protoko\u0142u Matter zosta\u0142 oficjalnie wprowadzony na rynek. Jest to jeden z pierwszych czujnik\xf3w dymu w bran\u017Cy z certyfikatem Matter 1.2.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nHS1SA-M obs\u0142uguje cztery g\u0142\xf3wne ekosystemy inteligentnego domu: Apple HomeKit, Amazon Alexa, Google Home i Samsung SmartThings.\\n\\n:::\\n\\n## Kluczowe cechy\\n\\n- **Certyfikat Matter 1.2** \u2014 interoperacyjno\u015B\u0107 mi\u0119dzy markami i ekosystemami\\n- **Czujnik dymu fotoelektryczny** \u2014 szybka reakcja na r\xf3\u017Cne rodzaje dymu po\u017Carowego\\n- **Komunikaty g\u0142osowe** \u2014 wiele j\u0119zyk\xf3w do wyboru, jasne przekazywanie informacji o zagro\u017Ceniu\\n- **Funkcja autotestu** \u2014 regularne samokontrole zapewniaj\u0105ce prawid\u0142owe dzia\u0142anie urz\u0105dzenia\\n- **Powiadomienia zdalne** \u2014 natychmiastowe powiadomienia alarmowe w aplikacji mobilnej\\n\\n## Kompatybilno\u015B\u0107\\n\\nHS1SA-M mo\u017Cna bezproblemowo zintegrowa\u0107 z g\u0142\xf3wnymi platformami inteligentnego domu. U\u017Cytkownicy mog\u0105 bezpo\u015Brednio sterowa\u0107 urz\u0105dzeniem i zarz\u0105dza\u0107 nim przez telefon bez konieczno\u015Bci stosowania dodatkowej bramki.\\n\\nOdwied\u017A [Centrum produktowe](/docs/tutorial-basics/create-a-page), aby dowiedzie\u0107 si\u0119 wi\u0119cej."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/pl/blog/long-blog-post","source":"@site/i18n/pl/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Historia rozwoju Heiman Technology","description":"Od za\u0142o\u017Cenia w 2005 roku Heiman Technology przeby\u0142o ju\u017C ponad 20 lat rozwoju. W tym artykule przybli\u017Cymy najwa\u017Cniejsze kamienie milowe w historii Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/tags/heiman","description":"Aktualno\u015Bci zwi\u0105zane z Heiman Technology"}],"readingTime":1.21,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Historia rozwoju Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman oficjalnie wprowadza inteligentny czujnik dymu z obs\u0142ug\u0105 protoko\u0142u Matter","permalink":"/heiman-wiki-public/pl/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology uznane za krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach","permalink":"/heiman-wiki-public/pl/blog/first-blog-post"}},"content":"Od za\u0142o\u017Cenia w 2005 roku Heiman Technology przeby\u0142o ju\u017C ponad 20 lat rozwoju. W tym artykule przybli\u017Cymy najwa\u017Cniejsze kamienie milowe w historii Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 - Za\u0142o\u017Cenie firmy\\n\\nShenzhen Heiman Technology Co., Ltd. zosta\u0142a oficjalnie za\u0142o\u017Cona, rozpoczynaj\u0105c dzia\u0142alno\u015B\u0107 w dziedzinie czujnik\xf3w ochrony mienia.\\n\\n## 2006 - Pocz\u0105tek internacjonalizacji\\n\\nWiele produkt\xf3w uzyska\u0142o certyfikat CE Unii Europejskiej i nawi\u0105zano wsp\xf3\u0142prac\u0119 z China Mobile.\\n\\n## 2011 - Prze\u0142om w certyfikacji mi\u0119dzynarodowej\\n\\nWiele produkt\xf3w uzyska\u0142o certyfikaty EN54-7 i EN14604 Unii Europejskiej, co \u015Bwiadczy o osi\u0105gni\u0119ciu mi\u0119dzynarodowego poziomu jako\u015Bci.\\n\\n## 2012 - Transformacja w kierunku inteligentnego domu\\n\\nPe\u0142ne uruchomienie projektu inteligentnego domu. Heiman przekszta\u0142ci\u0142o si\u0119 w przedsi\u0119biorstwo specjalizuj\u0105ce si\u0119 w badaniach, rozwoju, produkcji i sprzeda\u017Cy produkt\xf3w do inteligentnego domu.\\n\\n## 2017 - Znacz\u0105cy prze\u0142om\\n\\n- Opracowanie pierwszego w Chinach czujnika dymu NB-IoT\\n- Zdobycie 2 nagr\xf3d Red Dot Design Award\\n- Uzyskanie certyfikatu MFi i statusu producenta Apple\\n\\n## 2020 - Wsparcie kapita\u0142owe\\n\\nZako\u0144czenie rundy finansowania A, inwestorem by\u0142a grupa Shenzhen\u9AD8\u65B0\u6295, uzyskanie tytu\u0142u \u201Especjalistycznego i zaawansowanego ma\u0142ego i \u015Bredniego przedsi\u0119biorstwa\\" prowincji Guangdong.\\n\\n## 2022 - Uznanie na szczeblu krajowym\\n\\nUzyskanie statusu krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach. Seria K1 zdoby\u0142a nagrod\u0119 Red Dot Design Award.\\n\\n## 2023 - Liderstwo w mi\u0119dzynarodowych standardach\\n\\nLaboratorium badawcze Heiman oficjalnie uzyska\u0142o certyfikat CNAS. Czujniki dymu i tlenku w\u0119gla jako pierwsze otrzyma\u0142y certyfikat Matter 1.2.\\n\\n## 2024 - Do chwili obecnej\\n\\nNieustanna innowacja, pog\u0142\u0119bianie dzia\u0142a\u0144 w czterech g\u0142\xf3wnych obszarach: inteligentne bezpiecze\u0144stwo po\u017Carowe, gazowe, opieka nad seniorami i inteligentne czujniki. Dostarczanie wysokiej jako\u015Bci produkt\xf3w i us\u0142ug klientom w ponad 100 krajach na ca\u0142ym \u015Bwiecie."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/pl/blog/first-blog-post","source":"@site/i18n/pl/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology uznane za krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach","description":"W 2022 roku Heiman Technology, dzi\u0119ki swojemu g\u0142\u0119bokiemu do\u015Bwiadczeniu technologicznemu i innowacyjno\u015Bci w dziedzinie inteligentnych czujnik\xf3w, zosta\u0142o oficjalnie uznane za krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/tags/heiman","description":"Aktualno\u015Bci zwi\u0105zane z Heiman Technology"}],"readingTime":0.47,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/pl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology uznane za krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Historia rozwoju Heiman Technology","permalink":"/heiman-wiki-public/pl/blog/long-blog-post"}},"content":"W 2022 roku Heiman Technology, dzi\u0119ki swojemu g\u0142\u0119bokiemu do\u015Bwiadczeniu technologicznemu i innowacyjno\u015Bci w dziedzinie inteligentnych czujnik\xf3w, zosta\u0142o oficjalnie uznane za krajowego \u201Ema\u0142ego giganta\\" specjalizuj\u0105cego si\u0119 w nowych i zaawansowanych technologiach.\\n\\n{/* truncate */}\\n\\nTo krajowe wyr\xf3\u017Cnienie jest wyrazem uznania dla Heiman Technology w zakresie specjalizacji, precyzji, unikalno\u015Bci i innowacyjno\u015Bci. Heiman b\u0119dzie nadal rozwija\u0107 inteligentne bezpiecze\u0144stwo po\u017Carowe, gazowe, opiek\u0119 nad seniorami i inteligentne czujniki, stale dostarczaj\u0105c klientom wysokiej jako\u015Bci produkty i us\u0142ugi.\\n\\nWcze\u015Bniej Heiman Technology uzyska\u0142o ju\u017C wiele autorytatywnych certyfikat\xf3w, w tym krajowe przedsi\u0119biorstwo wysokich technologii oraz specjalistyczne i zaawansowane ma\u0142e i \u015Brednie przedsi\u0119biorstwo prowincji Guangdong."}]}}')}}]);